import{_ as a,o as t,c as n,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Tracium Engine","description":"","frontmatter":{},"headers":[],"relativePath":"engine/overview.md","filePath":"engine/overview.md"}'),s={name:"engine/overview.md"};function r(l,e,o,c,d,p){return t(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="tracium-engine" tabindex="-1">Tracium Engine <a class="header-anchor" href="#tracium-engine" aria-label="Permalink to &quot;Tracium Engine&quot;">​</a></h1><p>Tracium Engine (CSE — Code State Engine) is the execution recording core. It compiles Java code, launches a JVM with JDI attached, and captures every execution step into a UEF trace.</p><h2 id="modules" tabindex="-1">Modules <a class="header-anchor" href="#modules" aria-label="Permalink to &quot;Modules&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tracium-engine/</span></span>
<span class="line"><span>  engine-core/              # State model, timeline, UEF serializer</span></span>
<span class="line"><span>  engine-java-jdi-adapter/  # Java execution via JDI</span></span>
<span class="line"><span>  engine-service/           # Spring Boot REST API</span></span></code></pre></div><ul><li><strong>engine-core</strong> — language-agnostic. Owns the state model, timeline engine, and UEF serializer.</li><li><strong>engine-java-jdi-adapter</strong> — Java-specific. Compiles source, launches JVM, attaches JDI, captures events.</li><li><strong>engine-service</strong> — Spring Boot application with REST endpoints.</li></ul><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Language</td><td>Java 26</td></tr><tr><td>Framework</td><td>Spring Boot 4.0.5</td></tr><tr><td>Build</td><td>Gradle 9.4.1</td></tr><tr><td>Debugger</td><td>JDI (Java Debug Interface)</td></tr><tr><td>Serialization</td><td>Jackson</td></tr></tbody></table><h2 id="running" tabindex="-1">Running <a class="header-anchor" href="#running" aria-label="Permalink to &quot;Running&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tracium-engine</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :engine-service:bootRun</span></span></code></pre></div><p>Starts on <code>http://localhost:8080</code>.</p><h2 id="what-it-captures" tabindex="-1">What It Captures <a class="header-anchor" href="#what-it-captures" aria-label="Permalink to &quot;What It Captures&quot;">​</a></h2><p>For every execution step:</p><ul><li>Stack frames (method name, declaring type, local variables, parameters)</li><li>Heap objects (fields, array elements, reference graph)</li><li>State deltas (before/after values for every mutation)</li><li>Event type (VARIABLE_ASSIGNED, OBJECT_ALLOCATED, FIELD_UPDATED, etc.)</li><li>Source anchor (file, symbol, line number)</li></ul>`,13)])])}const g=a(s,[["render",r]]);export{u as __pageData,g as default};
